const entries = $input.all().map((entry) => entry.json).filter((entry) => entry && entry.document);
const cartDocs = entries.map((raw) => {
  const fields = raw.document.fields || {};
  const items = [];
  if (fields.items?.arrayValue?.values) {
    for (const value of fields.items.arrayValue.values) {
      if (value.mapValue?.fields) {
        const itemFields = value.mapValue.fields;
        items.push({
          sku: itemFields.sku?.stringValue || '',
          product_name: itemFields.product_name?.stringValue || '',
          price: Number(itemFields.price?.doubleValue ?? itemFields.price?.integerValue ?? 0),
          quantity: Number(itemFields.quantity?.integerValue ?? itemFields.quantity?.doubleValue ?? 1),
        });
      }
    }
  }

  return {
    updatedAt: fields.updated_at?.stringValue || fields.created_at?.stringValue || '',
    items,
  };
}).sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)));

const mergedBySku = new Map();
for (const doc of cartDocs) {
  for (const item of doc.items) {
    const sku = String(item.sku || '').trim();
    if (!sku) {
      continue;
    }

    const current = mergedBySku.get(sku);
    if (current) {
      current.quantity += Number(item.quantity || 0);
      if (!current.product_name && item.product_name) {
        current.product_name = item.product_name;
      }
      if (!current.price && item.price) {
        current.price = item.price;
      }
    } else {
      mergedBySku.set(sku, {
        sku,
        product_name: String(item.product_name || '').trim(),
        price: Number(item.price || 0),
        quantity: Number(item.quantity || 0),
      });
    }
  }
}

const items = Array.from(mergedBySku.values()).filter((item) => item.sku && item.quantity > 0);
const total = Math.round(items.reduce((sum, item) => sum + (Number(item.price || 0) * Number(item.quantity || 0)), 0) * 100) / 100;
const itemCount = items.reduce((sum, item) => sum + Number(item.quantity || 0), 0);

if (items.length === 0) {
  return [{ json: { success: true, empty: true, message: 'Carrinho vazio.', items: [], total: 0, item_count: 0 } }];
}

return [{ json: { success: true, empty: false, items, total, item_count: itemCount } }];

const data = $input.first().json;
const action = 'view';
const tenantId = data._tenantId;
const cartId = data._cartId;
const baseUrl = `https://firestore.googleapis.com/v1/projects/saas-manu-project/databases/(default)/documents/tenants/${tenantId}`;

if (action === 'delete' && cartId) {
  return [{ json: { method: 'DELETE', url: `${baseUrl}/carts/${cartId}`, body: null } }];
}

const itemsArray = (data.items || []).map(i => ({
  mapValue: {
    fields: {
      sku: { stringValue: i.sku || '' },
      product_name: { stringValue: i.product_name || '' },
      price: { doubleValue: i.price },
      quantity: { integerValue: String(i.quantity) },
    }
  }
}));

const body = {
  fields: {
    phone: { stringValue: data._phone || '' },
    customer_name: { stringValue: data._customerName || '' },
    customer_id: { stringValue: data._customerId || '' },
    items: { arrayValue: { values: itemsArray } },
    total: { doubleValue: data.total || 0 },
    status: { stringValue: 'open' },
    updated_at: { stringValue: new Date().toISOString() }
  }
};

if (action === 'create') {
  body.fields.created_at = { stringValue: new Date().toISOString() };
  return [{ json: { method: 'POST', url: `${baseUrl}/carts`, body } }];
}

if (action === 'update' && cartId) {
  const mask = 'updateMask.fieldPaths=items&updateMask.fieldPaths=total&updateMask.fieldPaths=status&updateMask.fieldPaths=updated_at';
  return [{ json: { method: 'PATCH', url: `${baseUrl}/carts/${cartId}?${mask}`, body } }];
}

return [{ json: { method: 'NONE' } }];

const prev = $('Lógica do Carrinho').first().json;
const { _action, _cartId, _tenantId, _phone, _customerName, _customerId, ...clean } = prev;
return [{ json: clean }];
